import { describe, expect, it } from 'vitest';
import {
  isInsideCausalDiamond,
  causalDiamond,
  causalDiamondBoundary,
} from './causal-diamond';
import type { SpacetimeEvent } from './causal-topology';
import { LIGHT_PICOLORENZO_LY, toPicolorenzos } from './math';

// ─── Fixtures ──────────────────────────────────────────────────────

const NOW_PLO = toPicolorenzos(new Date(Date.UTC(2026, 3, 13, 0, 0, 0)));
const AGE_PLO = 100; // observer age in picolorenzos

const observer: SpacetimeEvent = {
  id: 'observer',
  label: 'Observer',
  x: 0,
  y: 0,
  z: 0,
  pLo: NOW_PLO,
};

const birthEvent: SpacetimeEvent = {
  id: 'birth',
  label: 'Birth',
  x: 0,
  y: 0,
  z: 0,
  pLo: NOW_PLO - AGE_PLO,
};

const deathEvent: SpacetimeEvent = {
  id: 'death',
  label: 'Death',
  x: 0,
  y: 0,
  z: 0,
  pLo: NOW_PLO,
};

/** Midpoint: same location, halfway between birth and death. */
const midpointEvent: SpacetimeEvent = {
  id: 'midpoint',
  label: 'Midpoint',
  x: 0,
  y: 0,
  z: 0,
  pLo: NOW_PLO - AGE_PLO / 2,
};

/** Far past: well before birth. */
const farPastEvent: SpacetimeEvent = {
  id: 'far-past',
  label: 'Far Past',
  x: 0,
  y: 0,
  z: 0,
  pLo: NOW_PLO - AGE_PLO * 10,
};

/** Far future: well after death. */
const farFutureEvent: SpacetimeEvent = {
  id: 'far-future',
  label: 'Far Future',
  x: 0,
  y: 0,
  z: 0,
  pLo: NOW_PLO + AGE_PLO * 10,
};

/** Far away: spatially distant, spacelike from both birth and death. */
const farAwayEvent: SpacetimeEvent = {
  id: 'far-away',
  label: 'Far Away',
  x: AGE_PLO * LIGHT_PICOLORENZO_LY * 100,
  y: 0,
  z: 0,
  pLo: NOW_PLO - AGE_PLO / 2,
};

/** Very distant: extremely far away for outside-diamond check. */
const veryDistantEvent: SpacetimeEvent = {
  id: 'very-distant',
  label: 'Very Distant',
  x: AGE_PLO * LIGHT_PICOLORENZO_LY * 1000,
  y: 0,
  z: 0,
  pLo: NOW_PLO - AGE_PLO / 2,
};

// ─── isInsideCausalDiamond ─────────────────────────────────────────

describe('isInsideCausalDiamond', () => {
  it('event at midpoint (same location, halfway) is inside', () => {
    expect(isInsideCausalDiamond(birthEvent, deathEvent, midpointEvent)).toBe(
      true
    );
  });

  it('event far in the past (before birth) is outside', () => {
    expect(isInsideCausalDiamond(birthEvent, deathEvent, farPastEvent)).toBe(
      false
    );
  });

  it('event far in the future (after death) is outside', () => {
    expect(isInsideCausalDiamond(birthEvent, deathEvent, farFutureEvent)).toBe(
      false
    );
  });

  it('event far away spatially (spacelike from both) is outside', () => {
    expect(isInsideCausalDiamond(birthEvent, deathEvent, farAwayEvent)).toBe(
      false
    );
  });

  it('birth event itself is inside (here)', () => {
    expect(isInsideCausalDiamond(birthEvent, deathEvent, birthEvent)).toBe(
      true
    );
  });

  it('death event itself is inside (here)', () => {
    expect(isInsideCausalDiamond(birthEvent, deathEvent, deathEvent)).toBe(
      true
    );
  });
});

// ─── causalDiamond ─────────────────────────────────────────────────

describe('causalDiamond', () => {
  const allEvents = [
    midpointEvent,
    farPastEvent,
    farFutureEvent,
    farAwayEvent,
    veryDistantEvent,
  ];

  const diamond = causalDiamond(observer, AGE_PLO, allEvents);

  it('produces correct source identifier', () => {
    expect(diamond.source).toBe('GnosisCausalDiamond');
  });

  it('insideCount + outsideCount equals total events', () => {
    expect(diamond.insideCount + diamond.outsideCount).toBe(allEvents.length);
  });

  it('insideFraction in [0, 1]', () => {
    expect(diamond.insideFraction).toBeGreaterThanOrEqual(0);
    expect(diamond.insideFraction).toBeLessThanOrEqual(1);
  });

  it('an event at the observer location between birth and death is inside', () => {
    const body = diamond.bodies.find((b) => b.event.id === 'midpoint');
    expect(body).toBeDefined();
    expect(body!.insideDiamond).toBe(true);
  });

  it('a very distant event is outside', () => {
    const body = diamond.bodies.find((b) => b.event.id === 'very-distant');
    expect(body).toBeDefined();
    expect(body!.insideDiamond).toBe(false);
  });
});

// ─── causalDiamondBoundary ─────────────────────────────────────────

describe('causalDiamondBoundary', () => {
  const origin: SpacetimeEvent = {
    id: 'origin',
    label: 'Origin',
    x: 0,
    y: 0,
    z: 0,
    pLo: NOW_PLO - AGE_PLO / 2,
  };

  it('produces requested number of points', () => {
    const boundary = causalDiamondBoundary(birthEvent, deathEvent, origin, 40);
    expect(boundary.length).toBe(40);
  });

  it('all boundary points have valid Penrose coordinates (bounded [-1,1])', () => {
    const boundary = causalDiamondBoundary(birthEvent, deathEvent, origin, 40);
    for (const pt of boundary) {
      expect(pt.penroseTime).toBeGreaterThanOrEqual(-1);
      expect(pt.penroseTime).toBeLessThanOrEqual(1);
      expect(pt.penroseSpace).toBeGreaterThanOrEqual(-1);
      expect(pt.penroseSpace).toBeLessThanOrEqual(1);
    }
  });
});

// ─── Wider diamond captures more events ────────────────────────────

describe('diamond width scaling', () => {
  it('larger agePLo leads to more bodies inside (wider diamond)', () => {
    // Scatter events at moderate distances
    const scatterEvents: SpacetimeEvent[] = [];
    for (let i = 0; i < 20; i++) {
      const offset = (i - 10) * 5;
      scatterEvents.push({
        id: `scatter-${i}`,
        label: `Scatter ${i}`,
        x: offset * LIGHT_PICOLORENZO_LY * 0.3,
        y: 0,
        z: 0,
        pLo: NOW_PLO - 50 + offset,
      });
    }

    const narrowDiamond = causalDiamond(observer, 20, scatterEvents);
    const wideDiamond = causalDiamond(observer, 200, scatterEvents);

    expect(wideDiamond.insideCount).toBeGreaterThanOrEqual(
      narrowDiamond.insideCount
    );
  });
});
